export function sieveOfEratosthenes(n: number): number[] {
  if (n < 2) return [];
  const sieve: boolean[] = new Array(n + 1).fill(true);
  sieve[0] = false;
  sieve[1] = false;
  for (let i = 2; i * i <= n; i++) {
    if (sieve[i]) {
      for (let j = i * i; j <= n; j += i) sieve[j] = false;
    }
  }
  const primes: number[] = [];
  for (let i = 2; i <= n; i++) if (sieve[i]) primes.push(i);
  return primes;
}

export function primeFactorize(n: number): number[] {
  if (n < 2) return [];
  const factors: number[] = [];
  let m = n;
  for (let d = 2; d * d <= m; d++) {
    while (m % d === 0) {
      factors.push(d);
      m = Math.floor(m / d);
    }
  }
  if (m > 1) factors.push(m);
  return factors;
}

export function modPow(base: number, exp: number, mod: number): number {
  if (mod === 1) return 0;
  let result = 1;
  let b = ((base % mod) + mod) % mod;
  let e = exp;
  while (e > 0) {
    if (e & 1) result = (result * b) % mod;
    b = (b * b) % mod;
    e = Math.floor(e / 2);
  }
  return result;
}

export function extendedGcd(a: number, b: number): [number, number, number] {
  let oldR = a, r = b;
  let oldS = 1, s = 0;
  let oldT = 0, t = 1;
  while (r !== 0) {
    const q = Math.floor(oldR / r);
    [oldR, r] = [r, oldR - q * r];
    [oldS, s] = [s, oldS - q * s];
    [oldT, t] = [t, oldT - q * t];
  }
  if (oldR < 0) return [-oldR, -oldS, -oldT];
  return [oldR, oldS, oldT];
}

function egcd(a: number, b: number): [number, number, number] {
  let oldR = a, r = b;
  let oldS = 1, s = 0;
  let oldT = 0, t = 1;
  while (r !== 0) {
    const q = Math.floor(oldR / r);
    [oldR, r] = [r, oldR - q * r];
    [oldS, s] = [s, oldS - q * s];
    [oldT, t] = [t, oldT - q * t];
  }
  if (oldR < 0) return [-oldR, -oldS, -oldT];
  return [oldR, oldS, oldT];
}

export function modInverse(a: number, m: number): number | null {
  if (m <= 0) return null;
  const [g, x] = egcd(((a % m) + m) % m, m);
  if (g !== 1) return null;
  return ((x % m) + m) % m;
}

export function binomialCoeff(n: number, k: number): number {
  if (k < 0 || k > n) return 0;
  let kk = k;
  if (kk > n - kk) kk = n - kk;
  let result = 1;
  for (let i = 0; i < kk; i++) {
    result = (result * (n - i)) / (i + 1);
  }
  return Math.round(result);
}

export function integerSqrt(n: number): number {
  if (n < 0) return 0;
  if (n < 2) return n;
  let x = Math.floor(Math.sqrt(n));
  while (x * x > n) x--;
  while ((x + 1) * (x + 1) <= n) x++;
  return x;
}

export function digitSum(n: number): number {
  let m = Math.abs(Math.trunc(n));
  let sum = 0;
  while (m > 0) {
    sum += m % 10;
    m = Math.floor(m / 10);
  }
  return sum;
}
